namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Forklift A", "Warehouse 1", new DateTime(2026, 3, 10)),
            new(2, "Conveyor Belt B", "Warehouse 2", new DateTime(2026, 4, 22)),
            new(3, "Hydraulic Press C", "Factory Floor", new DateTime(2026, 1, 15)),
            new(4, "CNC Lathe D", "Machine Shop", new DateTime(2025, 12, 5)),
            new(5, "Welding Station E", "Assembly Bay", new DateTime(2026, 5, 1)),
            new(6, "Compressor F", "Utility Room", new DateTime(2026, 2, 18)),
            new(7, "Pallet Jack G", "Loading Dock", new DateTime(2026, 4, 30)),
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@inject PersistentComponentState PersistentState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;
    private PersistingComponentStateSubscription persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        persistingSubscription = PersistentState.RegisterOnPersisting(PersistData);

        if (!PersistentState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            // First render (prerender): fetch from service and persist
            items = await EquipmentService.GetEquipmentAsync();
        }
        else
        {
            // Interactive render: use the persisted data — no second fetch
            items = restored;
        }
    }

    private Task PersistData()
    {
        PersistentState.PersistAsJson("equipment", items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        persistingSubscription.Dispose();
    }
}

